#include<bits/stdc++.h>
#define pii pair<int,int>
#define mkp make_pair
using namespace std;
const int N=1001;
vector<pii> mp[N];
int dis[N],cnt[N],n,m;
bool vis[N];
bool spfa(int x)
{
    queue<int> q;
    q.push(x);
    memset(dis,0x3f,sizeof(dis));
    memset(cnt,0,sizeof(cnt));
    memset(vis,0,sizeof(vis));
    dis[x]=0;
    while(!q.empty())
    {
        int t=q.front();
        q.pop();
        vis[t]=0;
        for(pii i:mp[t])
        {
            int v=i.first,val=i.second;
            if(dis[v]>dis[t]+val)
            {
                dis[v]=dis[t]+val;
                if(!vis[v])
                {
                    cnt[v]++;
                    if(cnt[v]>n)
                    {
                        return true;
                    }
                    vis[v]=1;
                    q.push(v);
                }
            }
        }
    }
    return false;
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        int u,v,w;
        scanf("%d%d%d",&u,&v,&w);
        mp[u].push_back(mkp(v,-w));
    }
    if(spfa(1))
    {
        printf("Forever love");
        return 0;
    }
    int ans1=dis[n],ans2;
    if(spfa(n))
    {
        printf("Forever love");
        return 0;
    }
    ans2=dis[1];
    printf("%d",min(ans1,ans2));
    return 0;
}
